"use client";
import React from "react";
import { MinusIcon, PlusIcon } from "./icons";
import { CartItem } from "@/app/page";

interface Props {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <div className="flex flex-col h-full bg-white border-l border-gray-100 reveal-anim">
   {/* Dynamic Header */}
   <div className="p-8 pb-6 border-b border-gray-50">
    <div className="flex items-center justify-between mb-5">
     <h2 className="text-[22px] font-extrabold tracking-tight text-gray-900">Корзина</h2>
     <span className="px-2.5 py-1 bg-gray-50 text-[11px] font-extrabold text-gray-400 rounded-lg">
      {cart.length} товаров
     </span>
    </div>

    <div className="bg-gray-50/50 rounded-2xl p-4 border border-gray-100 group cursor-pointer hover:bg-gray-50 transition-all">
     <div className="flex items-center gap-3">
      <div className="w-2 h-2 rounded-full bg-pink-500 animate-pulse" />
      <div className="flex-1 min-w-0">
       <p className="text-[13px] font-bold text-gray-900 truncate">улица Академика Янгеля</p>
       <p className="text-[11px] font-bold text-green-600 uppercase tracking-widest mt-0.5">Доставим за 15 мин</p>
      </div>
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-gray-300">
       <path d="m6 9 6 6 6-6" />
      </svg>
     </div>
    </div>
   </div>

   {/* Main List Area */}
   <div className="flex-1 overflow-y-auto px-8 py-6 space-y-8 scrollbar-hide">
    {cart.length === 0 ? (
     <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
      <div className="w-24 h-24 bg-gray-50 rounded-[40px] flex items-center justify-center mb-6">
       <span className="text-5xl">🥐</span>
      </div>
      <p className="text-[15px] font-extrabold text-gray-900">Запах свежего хлеба...</p>
      <p className="text-[12px] font-bold text-gray-400 mt-1.5 max-w-[200px] mx-auto">но в корзине пока пусто. Давайте это исправим!</p>
     </div>
    ) : (
     <div className="space-y-6">
      {cart.map((item) => (
       <div key={item.id} className="flex gap-4 group">
        <div className="w-20 h-20 bg-gray-50 rounded-2xl flex-shrink-0 flex items-center justify-center border border-gray-100 group-hover:bg-pink-50/30 transition-colors duration-300">
         <div className="w-12 h-12 bg-pink-500/5 rounded-full blur-xl absolute" />
        </div>

        <div className="flex-1 min-w-0 flex flex-col justify-between py-1">
         <div>
          <h4 className="text-[14px] font-bold text-gray-900 leading-snug line-clamp-2 pr-4">{item.name}</h4>
          <p className="text-[11px] font-bold text-gray-400 mt-1 uppercase tracking-wider">{item.price} ₽ / шт</p>
         </div>

         <div className="flex items-center justify-between mt-3">
          <div className="flex items-center bg-gray-50 border border-gray-100 rounded-xl px-1">
           <button onClick={() => onUpdateQuantity(item.id, -1)} className="p-2 text-gray-300 hover:text-pink-500 transition-colors">
            <MinusIcon size={12} />
           </button>
           <span className="text-[13px] font-extrabold w-6 text-center text-gray-900">{item.quantity}</span>
           <button onClick={() => onUpdateQuantity(item.id, 1)} className="p-2 text-gray-300 hover:text-pink-500 transition-colors">
            <PlusIcon size={12} />
           </button>
          </div>
          <span className="text-[14px] font-extrabold text-black">{item.price * item.quantity} ₽</span>
         </div>
        </div>
       </div>
      ))}
     </div>
    )}
   </div>

   {/* Checkout Summary */}
   <div className="p-8 bg-white border-t border-gray-50 shadow-[0_-8px_30px_rgba(0,0,0,0.02)]">
    <div className="space-y-3 mb-8">
     <div className="flex justify-between text-[13px] font-bold text-gray-400">
      <span>Подитог</span>
      <span className="text-gray-900">{total} ₽</span>
     </div>
     <div className="flex justify-between items-center text-[13px] font-bold text-gray-400">
      <span>Доставка — 15 мин</span>
      <span className="text-green-600">0 ₽</span>
     </div>
     <div className="flex justify-between items-baseline pt-2">
      <span className="text-[16px] font-extrabold text-gray-900">Итого</span>
      <span className="text-[28px] font-extrabold text-black tracking-tighter">{total} ₽</span>
     </div>
    </div>

    <button
     className="checkout-btn group"
     disabled={cart.length === 0}
    >
     <span>К оформлению заказа</span>
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="group-hover:translate-x-1.5 transition-transform duration-300">
      <path d="M5 12h14M12 5l7 7-7 7" />
     </svg>
    </button>
    <p className="text-[11px] font-bold text-gray-400 text-center mt-6 uppercase tracking-[0.15em] opacity-60">Secure Checkout Guarantee</p>
   </div>
  </div>
 );
};

export default CartSidebar;
