import React from "react";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div className="ux-p-card group reveal-anim h-full">
  {/* Visual Container */}
  <div className="img-box bg-gray-50/70 rounded-[28px] p-6 overflow-hidden">
   {discount && (
    <span className="absolute top-4 left-4 z-10 bg-white/90 backdrop-blur-md text-[10px] font-extrabold px-2.5 py-1 rounded-full shadow-sm text-pink-500">
     {discount}
    </span>
   )}
   <img
    src={image}
    alt={name}
    className="w-full h-full object-contain mix-blend-multiply transition-transform duration-700"
    loading="lazy"
   />
  </div>

  {/* Metadata & Actions */}
  <div className="flex flex-col flex-1 mt-1">
   <div className="flex flex-col gap-0.5 mb-4">
    <h3 className="text-[14px] font-bold leading-snug text-gray-900 group-hover:text-pink-500 transition-colors line-clamp-2 min-h-[40px]">
     {name}
    </h3>
    <p className="text-[11px] font-semibold text-gray-400 tracking-wide uppercase">
     {weight}
    </p>
   </div>

   <div className="mt-auto flex items-end justify-between">
    <div className="flex flex-col">
     {oldPrice && (
      <span className="text-[11px] text-gray-300 line-through font-bold mb-0.5 italic">
       {oldPrice} ₽
      </span>
     )}
     <span className="text-[17px] font-extrabold text-black tracking-tighter">
      {price} ₽
     </span>
    </div>

    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     className="pink-plus shadow-sm"
     title="В корзину"
    >
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round">
      <path d="M12 5v14M5 12h14" />
     </svg>
    </button>
   </div>

   <div className="mt-5 h-[1.5px] w-0 bg-pink-100 group-hover:w-full transition-all duration-700 rounded-full" />
  </div>
 </div>
);

export default ProductCard;
